setup:
function() {
    WebInspectorAudit._vt = {
        MIN_TAP_PX: 44,
        tapSelector: "button, a[href], input:not([type=\"hidden\"]), select, textarea, summary, [role=\"button\"], [role=\"link\"], [role=\"tab\"], [tabindex]:not([tabindex=\"-1\"])"
    };
    WebInspectorAudit._vt.visible = function(el) {
        if (!el || el.closest("[hidden], [aria-hidden=\"true\"]"))
            return false;
        let r = el.getBoundingClientRect();
        return r.width > 0 && r.height > 0;
    };
    WebInspectorAudit._vt.tapTargets = function() {
        return Array.from(document.querySelectorAll(WebInspectorAudit._vt.tapSelector)).filter(WebInspectorAudit._vt.visible);
    };
}

tests.test:
function() {
    let route = (location.hash && location.hash.length > 1) ? location.hash.replace(/^#/, "") : (location.pathname + location.search);
    return {level: "pass", route: route, href: location.href, origin: location.origin};
}

function() {
    let ok = location.protocol === "capacitor:" || /vettrack\.uk$/i.test(location.hostname) || location.hostname === "localhost";
    return {level: ok ? "pass" : "warn", protocol: location.protocol, hostname: location.hostname, note: ok ? "Expected VetTrack shell" : "Run on Capacitor or vettrack.uk for submit gate"};
}

function() {
    let vp = document.querySelector("meta[name=\"viewport\"]");
    let content = vp ? (vp.getAttribute("content") || "") : "";
    let ok = /width=device-width/i.test(content);
    return {level: ok ? "pass" : "fail", domNodes: vp ? [vp] : [], content: content || "(missing)"};
}

function() {
    let root = document.getElementById("clerk-auth-form-root");
    if (!root)
        return {level: "warn", note: "Not on /signin or /signup — navigate there first or N/A"};
    let dir = root.getAttribute("dir") || "";
    let ok = dir.toLowerCase() === "ltr";
    return {level: ok ? "pass" : "fail", domNodes: [root], dir: dir || "(unset)"};
}

function() {
    let inputs = Array.from(document.querySelectorAll("#clerk-auth-form-root input, .cl-formFieldInput input, input[name=\"identifier\"], input[type=\"email\"]"));
    if (!inputs.length)
        return {level: "warn", note: "No Clerk identifier inputs on this route"};
    let fail = inputs.filter(function(input) {
        let cap = (input.getAttribute("autocapitalize") || input.autocapitalize || "").toLowerCase();
        return cap !== "none" && cap !== "off";
    });
    return {level: fail.length ? "fail" : "pass", domNodes: fail, checked: inputs.length};
}

function() {
    let min = WebInspectorAudit._vt.MIN_TAP_PX;
    let fail = WebInspectorAudit._vt.tapTargets().filter(function(el) {
        let r = el.getBoundingClientRect();
        return Math.min(r.width, r.height) < min;
    });
    return {level: fail.length ? "fail" : "pass", domNodes: fail, minTapPx: min, failingCount: fail.length};
}

function() {
    let fab = document.querySelector("button.bottom-nav-float");
    if (!fab)
        return {level: "warn", note: "Shift chat FAB not found — sign in, eligible role, not on /signin"};
    let r = fab.getBoundingClientRect();
    let ok = Math.min(r.width, r.height) >= WebInspectorAudit._vt.MIN_TAP_PX;
    return {level: ok ? "pass" : "fail", domNodes: [fab], width: Math.round(r.width), height: Math.round(r.height)};
}

function() {
    let mains = WebInspectorAudit.Accessibility.getElementsByComputedRole("main");
    return {level: mains.length <= 1 ? "pass" : "fail", domNodes: mains.length > 1 ? mains : [], count: mains.length};
}

function() {
    let buttons = WebInspectorAudit.Accessibility.getElementsByComputedRole("button");
    let fail = buttons.filter(function(btn) {
        let p = WebInspectorAudit.Accessibility.getComputedProperties(btn);
        return !p || !p.label || !String(p.label).trim();
    });
    return {level: fail.length ? "fail" : "pass", domNodes: fail, failingCount: fail.length};
}

function() {
    let imgs = Array.from(document.querySelectorAll("img")).filter(WebInspectorAudit._vt.visible);
    let fail = imgs.filter(function(img) { return img.getAttribute("alt") === null; });
    return {level: fail.length ? "fail" : "pass", domNodes: fail, imagesChecked: imgs.length};
}

function() {
    let inputs = Array.from(document.querySelectorAll("input:not([type=\"hidden\"]):not([type=\"submit\"]):not([type=\"button\"]), select, textarea")).filter(WebInspectorAudit._vt.visible);
    let fail = [];
    inputs.forEach(function(input) {
        let id = input.id;
        let labelled = (id && document.querySelector("label[for=\"" + CSS.escape(id) + "\"]")) || input.closest("label") || input.getAttribute("aria-label") || input.getAttribute("aria-labelledby");
        if (!labelled)
            fail.push(input);
    });
    return {level: fail.length ? "fail" : "pass", domNodes: fail, failingCount: fail.length};
}

function() {
    let dialogs = WebInspectorAudit.Accessibility.getElementsByComputedRole("dialog");
    let fail = dialogs.filter(function(d) {
        let p = WebInspectorAudit.Accessibility.getComputedProperties(d);
        return !p || !p.label || !String(p.label).trim();
    });
    return {level: fail.length ? "fail" : "pass", domNodes: fail, dialogCount: dialogs.length};
}

function() {
    let fail = Array.from(document.querySelectorAll("[aria-hidden]:not([aria-hidden=\"true\"]):not([aria-hidden=\"false\"])"));
    return {level: fail.length ? "fail" : "pass", domNodes: fail};
}

function() {
    let lang = document.documentElement.getAttribute("lang");
    return {level: (lang && lang.trim().length) ? "pass" : "warn", lang: lang || "(unset)"};
}

function() {
    let overflow = document.documentElement.scrollWidth > window.innerWidth + 2;
    return {level: overflow ? "warn" : "pass", scrollWidth: document.documentElement.scrollWidth, innerWidth: window.innerWidth};
}

function() {
    let h1s = Array.from(document.querySelectorAll("h1")).filter(WebInspectorAudit._vt.visible);
    let fail = h1s.filter(function(h) { return h.getBoundingClientRect().height < 8; });
    return {level: fail.length ? "fail" : "pass", domNodes: fail, h1Count: h1s.length};
}
